#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <random>
#include <cmath>
#include <cstring>
#include <climits>

const int MAX_N = 200;
const int MAX_M = 10;
const int MAX_STACK_SIZE = 210;

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(42) {}
    void seed_time() { rng.seed(std::chrono::steady_clock::now().time_since_epoch().count()); }
    int an_int(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int stacks[MAX_M][MAX_STACK_SIZE];
    int stack_size[MAX_M];
    int box_stack[MAX_N + 1];
    int box_height[MAX_N + 1];
    long long energy;
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& initial_stacks) {
        N = n; M = m; energy = 0;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)initial_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                int box = initial_stacks[i][j] - 1;
                stacks[i][j] = box;
                box_stack[box] = i;
                box_height[box] = j;
            }
        }
    }

    void move_block(int first_box, int num_boxes, int dest) {
        int src = box_stack[first_box];
        int src_h = box_height[first_box];
        int dest_h = stack_size[dest];
        for (int i = 0; i < num_boxes; i++) {
            int box = stacks[src][src_h + i];
            stacks[dest][dest_h + i] = box;
            box_stack[box] = dest;
            box_height[box] = dest_h + i;
        }
        stack_size[src] = src_h;
        stack_size[dest] = dest_h + num_boxes;
        energy += num_boxes + 1;
    }

    void undo_move_block(int first_box, int num_boxes, int dest) {
        int src_h = stack_size[dest] - num_boxes;
        int orig_src = -1;
        int orig_h = -1;
        // first_box is now at position src_h in stack dest... no wait
        // After move_block, the boxes are at dest starting at dest_h = stack_size[dest] - num_boxes (before undo)
        // We need to move them back
        // Actually, let's track the original src from first_box's position before the move
        // This is complex, let me use a different undo strategy
        // For the look-ahead, I'll just copy state instead
        (void)first_box; (void)num_boxes; (void)dest;
    }

    void carry_out(int box) {
        int s = box_stack[box];
        stack_size[s]--;
    }
};

// Look-ahead: find minimum energy for extracting boxes [start_box, start_box+depth)
// Returns the minimum energy spent in those extractions
// Modifies S in place and restores it (or we use copies)
long long look_ahead(State& S, int start_box, int depth) {
    if (depth == 0 || start_box >= S.N) return 0;

    int box = start_box;
    int src = S.box_stack[box];
    int h = S.box_height[box];
    int num_on_top = S.stack_size[src] - 1 - h;

    if (num_on_top == 0) {
        // Free extraction
        S.carry_out(box);
        long long future = look_ahead(S, box + 1, depth - 1);
        // Undo carry_out: put box back on top of src
        S.stacks[src][h] = box;
        S.stack_size[src]++;
        S.box_stack[box] = src;
        S.box_height[box] = h;
        return future;
    }

    long long best_total = LLONG_MAX;
    int first_above = S.stacks[src][h + 1];

    // Save the block info for undo
    int saved_block[MAX_STACK_SIZE];
    for (int i = 0; i < num_on_top; i++) {
        saved_block[i] = S.stacks[src][h + 1 + i];
    }

    for (int d = 0; d < S.M; d++) {
        if (d == src) continue;

        int dest_h = S.stack_size[d];

        // Do move
        for (int i = 0; i < num_on_top; i++) {
            int b = saved_block[i];
            S.stacks[d][dest_h + i] = b;
            S.box_stack[b] = d;
            S.box_height[b] = dest_h + i;
        }
        S.stack_size[src] = h;
        S.stack_size[d] = dest_h + num_on_top;

        long long cost = num_on_top + 1;

        // Carry out box
        S.stack_size[src]--; // src stack now has h-1... wait no
        // Box is at position h in src. After moving the block above it, stack_size[src] = h.
        // But wait, box itself is at position h. stack_size[src] = h means the top is at h-1.
        // Hmm, let me think again. After move, stack_size[src] = h. Box is at position h...
        // but stack_size = h means indices 0..h-1 are valid. So box at position h is ABOVE the stack?
