        }
        S.carry_out(k);
    }
    return energy;
}

// Look-ahead with greedy rollout: try all 9 destinations for current box,
// then use greedy for the next 'rollout_depth' boxes, accumulate cost
int look_ahead_best_dest(const State& S, int target, int rollout_depth) {
    int src = S.box_stack[target];
    int h = S.box_height[target];
    int num_on_top = S.stack_size[src] - 1 - h;

    if (num_on_top == 0) return src;

    long long best_total = LLONG_MAX;
    int best_dest = (src + 1) % S.M;

    for (int d = 0; d < S.M; d++) {
        if (d == src) continue;

        // Make a copy and simulate this choice + rollout
        State copy = S;
        int first_above = copy.stacks[src][h + 1];
        copy.move_block_to(first_above, num_on_top, d);
        long long cost = num_on_top + 1;
        copy.carry_out(target);

        // Simulate next rollout_depth boxes with greedy
        int end_box = std::min(target + 1 + rollout_depth, copy.N);
        for (int k = target + 1; k < end_box; k++) {
            int ksrc = copy.box_stack[k];
            int kh = copy.box_height[k];
            int k_on_top = copy.stack_size[ksrc] - 1 - kh;
            if (k_on_top > 0) {
                int kdest = greedy_best_dest(copy, k);
                if (kdest == ksrc) kdest = (ksrc + 1) % copy.M;
                copy.move_block_to(copy.stacks[ksrc][kh + 1], k_on_top, kdest);
                cost += k_on_top + 1;
            }
            copy.carry_out(k);
        }

        if (cost < best_total) {
            best_total = cost;
            best_dest = d;
        }
    }

    return best_dest;
}

// Two-level look-ahead: try all 9 dests for current box, then for each,
// try all 9 dests for the next box (that needs a move), then greedy rollout.
int look_ahead_2level(const State& S, int target, int rollout_depth) {
    int src = S.box_stack[target];
    int h = S.box_height[target];
    int num_on_top = S.stack_size[src] - 1 - h;

    if (num_on_top == 0) return src;

    long long best_total = LLONG_MAX;
    int best_dest = (src + 1) % S.M;

    for (int d = 0; d < S.M; d++) {
        if (d == src) continue;

        // Make a copy and simulate this choice
        State S1 = S;
        int first_above = S1.stacks[src][h + 1];
        S1.move_block_to(first_above, num_on_top, d);
        long long cost = num_on_top + 1;
        S1.carry_out(target);

        // Find the next box that needs a move and try all dests for it
        long long best_inner = LLONG_MAX;
        int next_box = target + 1;

        // Skip free extractions
        while (next_box < S1.N) {
            int nsrc = S1.box_stack[next_box];
            int nh = S1.box_height[next_box];
            int n_on_top = S1.stack_size[nsrc] - 1 - nh;
            if (n_on_top > 0) break;
            S1.carry_out(next_box);
            next_box++;
        }

        if (next_box >= S1.N) {
            // All remaining are free
            if (cost < best_total) {
                best_total = cost;
                best_dest = d;
            }
            continue;
        }

        // Try all destinations for next_box
        int nsrc = S1.box_stack[next_box];
        int nh = S1.box_height[next_box];
        int n_on_top = S1.stack_size[nsrc] - 1 - nh;

        for (int d2 = 0; d2 < S1.M; d2++) {
            if (d2 == nsrc) continue;

            State S2 = S1;
            int first_above2 = S2.stacks[nsrc][nh + 1];
            S2.move_block_to(first_above2, n_on_top, d2);
            long long cost2 = n_on_top + 1;
            S2.carry_out(next_box);

            // Greedy rollout
            int end_box = std::min(next_box + 1 + rollout_depth, S2.N);
            for (int k = next_box + 1; k < end_box; k++) {
                int ksrc = S2.box_stack[k];
                int kh = S2.box_height[k];
                int k_on_top = S2.stack_size[ksrc] - 1 - kh;
                if (k_on_top > 0) {
                    int kdest = greedy_best_dest(S2, k);
                    if (kdest == ksrc) kdest = (ksrc + 1) % S2.M;
                    S2.move_block_to(S2.stacks[ksrc][kh + 1], k_on_top, kdest);
                    cost2 += k_on_top + 1;
                }
                S2.carry_out(k);
            }

            if (cost2 < best_inner) {
                best_inner = cost2;
            }
        }

        long long total = cost + best_inner;
        if (total < best_total) {
            best_total = total;
            best_dest = d;
        }
    }

    return best_dest;
}

long long simulate_full(const std::vector<std::vector<int>>& initial_stacks,
                        const int* plan, int N, int M) {
    State S;
    S.init_from(N, M, initial_stacks);
    long long energy = 0;
    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            S.move_block_to(S.stacks[src][h + 1], num_on_top, dest);
            energy += num_on_top + 1;
        }
        S.carry_out(k);
    }
    return energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();
    RGen.seed_time();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
    }

    // Phase 1: Look-ahead construction with 2-level branching + greedy rollout
    int best_plan[MAX_N];
    long long best_energy = 0;
    {
        State S;
        S.init_from(N, M, initial_stacks);

        for (int k = 0; k < N; k++) {
            int src = S.box_stack[k];
            int h = S.box_height[k];
            int num_on_top = S.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                best_plan[k] = src;
                S.carry_out(k);
                continue;
            }

            double time_left = 1.0 - elapsed_seconds();
            int rollout_depth;
            int use_2level;

            if (time_left > 0.7) {
                use_2level = 1;
                rollout_depth = 15;
            } else if (time_left > 0.3) {
                use_2level = 1;
                rollout_depth = 10;
            } else if (time_left > 0.1) {
                use_2level = 0;
                rollout_depth = 15;
            } else {
                use_2level = 0;
                rollout_depth = 5;
            }

            int dest;
            if (use_2level) {
