        int src = box_stack[box_above];
        int src_h = box_height[box_above];
        int dest_h = stack_size[dest];
        for (int i = 0; i < num_boxes; i++) {
            int b = stacks[src][src_h + i];
            stacks[dest][dest_h + i] = b;
