    void init_from(int n, int m, const std::vector<std::vector<int>>& initial_stacks) {
        N = n; M = m;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)initial_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                int box = initial_stacks[i][j] - 1;
                stacks[i][j] = box;
                box_stack[box] = i;
                box_height[box] = j;
            }
        }
