        for (int j = 0; j < S.stack_size[d]; j++) {
            int box_in_dest = S.stacks[d][j];
            if (box_in_dest > target && box_in_dest < target + 25) {
                int boxes_above_after = (S.stack_size[d] - 1 - j) + num_on_top;
