                            checkpoints[ci] = S;
                            cp_energy[ci] = running;
                        }
                    }
                    accepts_since_rebuild = 0;
                }
            }
        }
    }

    // Output using best_plan
    {
        State S;
        S.init_from(N, M, initial_stacks);
        for (int k = 0; k < N; k++) {
            int src = S.box_stack[k];
